def prove_3anibar(sys: System) -> Proof:
    """Remove a hypothesis from the second member of a biconditional.
    (Contributed by FL, 22-Jul-2008.)
    """
    lb = ProofBuilder(sys, "3anibar")
    h1 = lb.hyp("3anibar.1", "( ( φ ∧ ψ ∧ χ ) → ( θ ↔ ( χ ∧ τ ) ) )")
    s1 = lb.ref("s1", "( ( φ ∧ ψ ∧ χ ) → χ )", ref="simp3", note="simp3")
    res = lb.ref("res", "( ( φ ∧ ψ ∧ χ ) → ( θ ↔ τ ) )", s1, h1, ref="mpbirand", note="mpbirand")
    return lb.build(res)

def prove_3mix1(sys: System) -> Proof:
    """Introduction in triple disjunction.  (Contributed by NM, 4-Apr-1995.)"""
    lb = ProofBuilder(sys, "3mix1")
    s1 = lb.ref("s1", "( φ → ( φ ∨ ( ψ ∨ χ ) ) )", ref="orc", note="orc")
    s2 = lb.ref("s2", "( ( φ ∨ ψ ∨ χ ) ↔ ( φ ∨ ( ψ ∨ χ ) ) )", ref="3orass", note="3orass")
    res = lb.ref("res", "( φ → ( φ ∨ ψ ∨ χ ) )", s1, s2, ref="sylibr", note="sylibr")
    return lb.build(res)

def prove_3mix2(sys: System) -> Proof:
    """Introduction in triple disjunction.  (Contributed by NM, 4-Apr-1995.)"""
